import { ConvertibleUnit, FormatOptions, Unit } from '@dynatrace-sdk/units';
import type { TruncationMode } from '../../../../../../typography/text-ellipsis/TextEllipsis.js';
import { Formatter } from '../../../../types/formatter.js';
import { ChartLegendOrientation } from '../../../../types/legend.js';
/**
 * @internal
 */
export interface RangeItem {
    /**
     * Item's Lower limit inside the range
     */
    from: number;
    /**
     * Item's Upper limit inside the range
     */
    to: number;
    /**
     * Item's color
     * @defaultValue 'Background/Field/Neutral/Disabled'
     */
    color?: string;
}
/**
 * @internal
 */
export interface RangeLegendProps {
    /**
     * All the items to be added to the legend.
     * It is expected to receive an array of items that already has ordered and valid data.
     */
    items: RangeItem[];
    /**
     * Legend orientation
     * @defaultValue 'horizontal'
     */
    orientation?: ChartLegendOrientation;
    /**
     * Custom Formatter for the chart
     */
    formatter?: Formatter | FormatOptions<Unit, ConvertibleUnit>;
    /**
     * Truncation mode to use (start, middle, end)
     * Applied to all the parts that truncate text.
     * @defaultValue 'middle'
     */
    truncationMode?: TruncationMode;
    /**
     * Min value for the multi meter bar chart scale.
     * @defaultValue lowest item value
     */
    min?: number;
    /**
     * Max value for the multi meter bar chart scale.
     * @defaultValue highest item value
     */
    max?: number;
}
